// frontend/src/pages/Booking.js
import React, { useState, useEffect } from "react";
import {
  Container, Paper, Typography, TextField, Box,
  Button, ListItemButton, Drawer, CircularProgress, Card, CardContent
} from "@mui/material";
import {
  MapContainer, TileLayer, Marker, Polyline, Popup, useMapEvents
} from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../contexts/AuthContext";
import { io } from "socket.io-client";

const socket = io("http://localhost:5000");

export default function Booking() {
  const [pickup, setPickup] = useState(null);
  const [drop, setDrop] = useState(null);
  const [pickupAddress, setPickupAddress] = useState("");
  const [dropAddress, setDropAddress] = useState("");
  const [dropSuggestions, setDropSuggestions] = useState([]);
  const [route, setRoute] = useState(null);
  const [distance, setDistance] = useState(null);

  const [drawerOpen, setDrawerOpen] = useState(false);
  const [rideOptions, setRideOptions] = useState([]);
  const [selectedRide, setSelectedRide] = useState(null);

  const [lookingForDriver, setLookingForDriver] = useState(false);
  const [driver, setDriver] = useState(null);
  const [driverLocation, setDriverLocation] = useState(null);

  const { auth } = useAuth();
  const navigate = useNavigate();

  // 📍 Get current location
  useEffect(() => {
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const loc = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setPickup(loc);
        const addr = await getAddressFromCoords(loc.lat, loc.lng);
        setPickupAddress(addr);
      },
      (err) => console.error("Geolocation error:", err)
    );
  }, []);

  // 🌍 Reverse geocode
  const getAddressFromCoords = async (lat, lng) => {
    try {
      const res = await axios.get(
        `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json`
      );
      return res.data.display_name || "";
    } catch {
      return "";
    }
  };

  // 🔎 Drop suggestions
  const fetchSuggestions = async (query) => {
    if (!query) return;
    try {
      const res = await axios.get("https://nominatim.openstreetmap.org/search", {
        params: { q: query, format: "json", limit: 5 },
      });
      setDropSuggestions(res.data);
    } catch (err) {
      console.error("Suggestion fetch failed:", err);
    }
  };

  // 🛣 Route
  useEffect(() => {
    const fetchRoute = async () => {
      if (pickup && drop) {
        try {
          const res = await axios.get(
            `https://router.project-osrm.org/route/v1/driving/${pickup.lng},${pickup.lat};${drop.lng},${drop.lat}?overview=full&geometries=geojson`
          );
          const data = res.data.routes[0];
          setRoute(data.geometry.coordinates.map((c) => [c[1], c[0]]));
          setDistance((data.distance / 1000).toFixed(2));
        } catch (err) {
          console.error("Route fetch failed:", err);
        }
      }
    };
    fetchRoute();
  }, [pickup, drop]);

  // 🚖 Ride options
  useEffect(() => {
    if (distance) {
      setRideOptions([
        { id: "bike", name: "Bike", eta: "3 min", price: (distance * 10).toFixed(2), capacity: 1 },
        { id: "auto", name: "Auto", eta: "2 min", price: (distance * 15).toFixed(2), capacity: 3 },
        { id: "car", name: "Car", eta: "4 min", price: (distance * 20).toFixed(2), capacity: 4 },
      ]);
    }
  }, [distance]);

  // 📍 Map clicks
  function LocationMarker() {
    useMapEvents({
      async click(e) {
        setDrop(e.latlng);
        const addr = await getAddressFromCoords(e.latlng.lat, e.latlng.lng);
        setDropAddress(addr);
      },
    });
    return null;
  }

  // 🔥 Create ride request
  const handleFindRiders = async () => {
    try {
      const res = await axios.post(
        "http://localhost:5000/api/rides/create",
        { pickup: pickupAddress, drop: dropAddress, pickupCoords: pickup, dropCoords: drop },
        { headers: { Authorization: `Bearer ${auth?.token}` } }
      );
      socket.emit("newRide", res.data.ride);
      setDrawerOpen(true);
    } catch (err) {
      alert("Failed to create ride request");
    }
  };

  // 🚖 Request ride
  const handleRequestRide = () => {
    setLookingForDriver(true);
    socket.emit("rideRequested", {
      type: selectedRide,
      pickup: pickupAddress,
      drop: dropAddress,
      distance,
    });
  };

  // 🔔 Listen for driver updates
  useEffect(() => {
    socket.on("rideAccepted", (ride) => {
      setLookingForDriver(false);
      setDrawerOpen(false);
      setDriver(ride.driver);
    });
    socket.on("driverLocationUpdate", ({ coords }) => setDriverLocation(coords));
    socket.on("driverArrived", () => alert("🚖 Driver arrived!"));
    return () => {
      socket.off("rideAccepted");
      socket.off("driverLocationUpdate");
      socket.off("driverArrived");
    };
  }, []);

  // Icons
  const pickupIcon = new L.Icon({ iconUrl: "https://cdn-icons-png.flaticon.com/512/32/32339.png", iconSize: [25, 25] });
  const dropIcon = new L.Icon({ iconUrl: "https://cdn-icons-png.flaticon.com/512/684/684908.png", iconSize: [35, 35] });
  const driverIcon = new L.Icon({ iconUrl: "https://cdn-icons-png.flaticon.com/512/64/64113.png", iconSize: [35, 35] });

  return (
    <Container maxWidth="xl" sx={{ mt: 3 }}>
      <Box sx={{ display: "grid", gridTemplateColumns: "1fr 2fr", gap: 2 }}>
        {/* Left panel */}
        <Paper sx={{ p: 3, borderRadius: 2 }}>
          <Typography variant="h6">Find a trip</Typography>
          <TextField fullWidth label="Pickup Address" value={pickupAddress} sx={{ mb: 2 }} />
          <TextField fullWidth label="Drop Address" value={dropAddress}
            onChange={(e) => { setDropAddress(e.target.value); fetchSuggestions(e.target.value); }}
            sx={{ mb: 2 }} />
          {dropSuggestions.map((s, i) => (
            <ListItemButton key={i} onClick={() => {
              setDrop({ lat: parseFloat(s.lat), lng: parseFloat(s.lon) });
              setDropAddress(s.display_name);
              setDropSuggestions([]);
            }}>{s.display_name}</ListItemButton>
          ))}
          <Button fullWidth variant="contained" sx={{ bgcolor: "black", mt: 2 }}
            onClick={handleFindRiders}>Find Riders</Button>

          {driver && (
            <Card sx={{ mt: 3, p: 2 }}>
              <CardContent>
                <Typography variant="h6">🚖 Driver Assigned</Typography>
                <Typography>Name: {driver.fullName}</Typography>
                <Typography>Phone: {driver.mobile}</Typography>
                <Typography>Vehicle: {driver.vehicle?.type} ({driver.vehicle?.plate})</Typography>
                <Box mt={2}>
                  <Button variant="contained" color="success" sx={{ mr: 2 }}>Call 📞</Button>
                  <Button variant="outlined" color="primary">Chat 💬</Button>
                </Box>
              </CardContent>
            </Card>
          )}
        </Paper>

        {/* Right panel: Map */}
        <Paper sx={{ p: 1, borderRadius: 2 }}>
          {pickup && (
            <MapContainer center={pickup} zoom={13} style={{ height: "600px", width: "100%" }}>
              <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
              {pickup && <Marker position={pickup} icon={pickupIcon}><Popup>You</Popup></Marker>}
              {drop && <Marker position={drop} icon={dropIcon}><Popup>Drop</Popup></Marker>}
              {driverLocation && <Marker position={driverLocation} icon={driverIcon}><Popup>Driver</Popup></Marker>}
              <LocationMarker />
              {route && <Polyline positions={route} pathOptions={{ color: "black", weight: 4 }} />}
            </MapContainer>
          )}
        </Paper>
      </Box>

      {/* Ride drawer */}
      <Drawer anchor="bottom" open={drawerOpen} onClose={() => setDrawerOpen(false)}>
        <Box sx={{ p: 3 }}>
          <Typography variant="h6">Choose a ride</Typography>
          {rideOptions.map((opt) => (
            <Box key={opt.id} onClick={() => setSelectedRide(opt.id)}
              sx={{ border: selectedRide === opt.id ? "2px solid black" : "1px solid #ccc", p: 2, mb: 2 }}>
              <Typography>{opt.name} • {opt.capacity} seats • ₹{opt.price}</Typography>
            </Box>
          ))}
          {lookingForDriver
            ? <CircularProgress />
            : <Button variant="contained" fullWidth onClick={handleRequestRide} disabled={!selectedRide}>Request Ride</Button>
          }
        </Box>
      </Drawer>
    </Container>
  );
}
